        function setupEffects() {
            // Nền hạt
            const particlesContainer = document.getElementById('particles-bg');
            if (particlesContainer){
                const particleCount = 20;
                for (let i = 0; i < particleCount; i++) {
                    const particle = document.createElement('div');
                    particle.className = 'particle';
                    particle.style.width = particle.style.height = `${Math.random() * 3 + 1}px`;
                    particle.style.top = `${Math.random() * 100}%`;
                    particle.style.left = `${Math.random() * 100}%`;
                    particle.style.animationDelay = `${Math.random() * 20}s`;
                    particle.style.animationDuration = `${Math.random() * 10 + 15}s`;
                    particlesContainer.appendChild(particle);
                }
            }

            // Phản hồi khi nhấp
            const cards = document.querySelectorAll('.status-card');
            cards.forEach(card => {
                card.addEventListener('click', function() {
                    this.classList.add('active-feedback');
                    setTimeout(() => {
                        this.classList.remove('active-feedback');
                    }, 400);
                });
            });
        }

        // --- Khởi tạo thực thi ---
        populateData();
        setupEffects();

    } catch (error) {
        console.error("Lỗi khi hiển thị thanh trạng thái tu tiên:", error);
        const container = document.querySelector('.card-grid');
        if (container) container.innerHTML = `<div style="color:red; padding:20px; text-align:center;">Tải thanh trạng thái thất bại: ${error.message}</div>`;
    }
})();
</script>
